/**
 * Auth Flow Integration Tests
 *
 * Integration tests for the authentication flow covering:
 * - Complete registration → login → token refresh flow
 * - Password reset flow
 * - Email verification flow
 * - Session management
 *
 * These tests verify the interaction between AuthModuleService,
 * AuthService (core), and related components.
 *
 * @module tests/integration/auth.integration.spec
 */

import { describe, it, expect, beforeEach, vi, type Mock } from 'vitest';
import { UserStatus } from '@prisma/client';

import { AuthModuleService } from '@/modules/_core/auth/auth.service';
import { AppException } from '@/core/exceptions/app.exception';
import type { AuthService, TokenUser } from '@/core/services/auth.service';
import type { EventService } from '@/core/services/event.service';
import type { RegisterRequest, LoginRequest } from '@/modules/_core/auth/auth.types';

// -----------------------------------------------------------------------------
// Test Utilities & Factories
// -----------------------------------------------------------------------------

/**
 * Creates a complete mock PrismaClient for integration testing
 */
function createIntegrationMockPrisma() {
  return {
    user: {
      findFirst: vi.fn(),
      findUnique: vi.fn(),
      findMany: vi.fn(),
      create: vi.fn(),
      update: vi.fn(),
      delete: vi.fn(),
      count: vi.fn(),
    },
    $transaction: vi.fn((callback: (prisma: unknown) => Promise<unknown>) => callback({})),
    $connect: vi.fn(),
    $disconnect: vi.fn(),
  };
}

/**
 * Creates a mock AuthService (core) that simulates real token operations
 */
function createIntegrationMockAuthService(): {
  hashPassword: Mock;
  verifyPassword: Mock;
  generateTokenPair: Mock;
  generateEmailVerificationToken: Mock;
  generatePasswordResetToken: Mock;
  verifyPasswordResetToken: Mock;
  invalidatePasswordResetToken: Mock;
  verifyEmailVerificationToken: Mock;
  invalidateEmailVerificationToken: Mock;
  refreshAccessToken: Mock;
  revokeAllUserTokens: Mock;
  getUserSessions: Mock;
} {
  // Store tokens for simulation
  const tokenStore = new Map<string, { userId: string; email: string; createdAt: string }>();
  let tokenCounter = 0;

  return {
    hashPassword: vi.fn().mockImplementation(async (password: string) => {
      // Simulate bcrypt hashing
      return `hashed_${password}_${Date.now()}`;
    }),

    verifyPassword: vi.fn().mockImplementation(async (password: string, hash: string) => {
      // Simple simulation - check if hash contains the password
      return hash.includes(`hashed_${password.substring(0, 10)}`);
    }),

    generateTokenPair: vi.fn().mockImplementation(async (user: TokenUser) => {
      tokenCounter++;
      const accessToken = `access_token_${user.id}_${tokenCounter}`;
      const refreshToken = `refresh_token_${user.id}_${tokenCounter}`;

      // Store refresh token data
      tokenStore.set(refreshToken, {
        userId: user.id,
        email: '',
        createdAt: new Date().toISOString(),
      });

      return {
        accessToken,
        refreshToken,
        expiresIn: 900000, // 15 minutes
        tokenType: 'Bearer' as const,
      };
    }),

    generateEmailVerificationToken: vi.fn().mockImplementation(async (userId: string, email: string) => {
      tokenCounter++;
      const token = `verify_email_${userId}_${tokenCounter}`;
      tokenStore.set(token, { userId, email, createdAt: new Date().toISOString() });
      return token;
    }),

    generatePasswordResetToken: vi.fn().mockImplementation(async (userId: string, email: string) => {
      tokenCounter++;
      const token = `reset_password_${userId}_${tokenCounter}`;
      tokenStore.set(token, { userId, email, createdAt: new Date().toISOString() });
      return token;
    }),

    verifyPasswordResetToken: vi.fn().mockImplementation(async (token: string) => {
      const data = tokenStore.get(token);
      if (!data || !token.startsWith('reset_password_')) {
        throw new AppException('INVALID_RESET_TOKEN', 401);
      }
      return data;
    }),

    invalidatePasswordResetToken: vi.fn().mockImplementation(async (token: string) => {
      tokenStore.delete(token);
    }),

    verifyEmailVerificationToken: vi.fn().mockImplementation(async (token: string) => {
      const data = tokenStore.get(token);
      if (!data || !token.startsWith('verify_email_')) {
        throw new AppException('INVALID_TOKEN', 401);
      }
      return data;
    }),

    invalidateEmailVerificationToken: vi.fn().mockImplementation(async (token: string) => {
      tokenStore.delete(token);
    }),

    refreshAccessToken: vi.fn().mockImplementation(async (refreshToken: string, getUserData: (userId: string) => Promise<TokenUser>) => {
      const data = tokenStore.get(refreshToken);
      if (!data || !refreshToken.startsWith('refresh_token_')) {
        throw new AppException('INVALID_REFRESH_TOKEN', 401);
      }

      // Get fresh user data
      const user = await getUserData(data.userId);

      // Generate new tokens
      tokenCounter++;
      const newAccessToken = `access_token_${user.id}_${tokenCounter}`;
      const newRefreshToken = `refresh_token_${user.id}_${tokenCounter}`;

      // Invalidate old token, store new
      tokenStore.delete(refreshToken);
      tokenStore.set(newRefreshToken, {
        userId: user.id,
        email: '',
        createdAt: new Date().toISOString(),
      });

      return {
        accessToken: newAccessToken,
        refreshToken: newRefreshToken,
        expiresIn: 900000,
        tokenType: 'Bearer' as const,
      };
    }),

    revokeAllUserTokens: vi.fn().mockImplementation(async (userId: string) => {
      // Remove all tokens for this user
      for (const [token, data] of tokenStore.entries()) {
        if (data.userId === userId) {
          tokenStore.delete(token);
        }
      }
    }),

    getUserSessions: vi.fn().mockResolvedValue([]),
  };
}

/**
 * Creates a mock EventService that tracks emitted events
 */
function createIntegrationMockEventService(): {
  emitCustom: Mock;
  getEmittedEvents: () => Array<{ event: string; data: unknown }>;
} {
  const emittedEvents: Array<{ event: string; data: unknown }> = [];

  return {
    emitCustom: vi.fn().mockImplementation(async (event: string, data: unknown) => {
      emittedEvents.push({ event, data });
    }),
    getEmittedEvents: () => [...emittedEvents],
  };
}

/**
 * Creates a mock user with roles for testing
 */
function createTestUser(overrides: Partial<{
  id: string;
  email: string;
  passwordHash: string;
  firstName: string;
  lastName: string;
  phone: string | null;
  avatar: string | null;
  organizationId: string | null;
  status: UserStatus;
  emailVerifiedAt: Date | null;
  lastLoginAt: Date | null;
  createdAt: Date;
  updatedAt: Date;
  deletedAt: Date | null;
  userRoles: Array<{
    role: {
      id: string;
      name: string;
      rolePermissions: Array<{
        permission: {
          resource: string;
          action: string;
        };
      }>;
    };
  }>;
}> = {}) {
  return {
    id: 'user_integration_test',
    email: 'integration@test.com',
    passwordHash: 'hashed_SecurePassword123!_1234567890',
    firstName: 'Integration',
    lastName: 'Test',
    phone: '+905551234567',
    avatar: null,
    organizationId: 'org_integration_test',
    status: UserStatus.ACTIVE,
    emailVerifiedAt: new Date(),
    lastLoginAt: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    userRoles: [
      {
        role: {
          id: 'role_owner',
          name: 'owner',
          rolePermissions: [
            { permission: { resource: 'menu', action: 'view' } },
            { permission: { resource: 'menu', action: 'create' } },
            { permission: { resource: 'menu', action: 'update' } },
            { permission: { resource: 'menu', action: 'delete' } },
            { permission: { resource: 'order', action: 'view' } },
            { permission: { resource: 'order', action: 'manage' } },
          ],
        },
      },
    ],
    ...overrides,
  };
}

// -----------------------------------------------------------------------------
// Integration Test Suite
// -----------------------------------------------------------------------------

describe('Auth Flow Integration', () => {
  let authModuleService: AuthModuleService;
  let mockPrisma: ReturnType<typeof createIntegrationMockPrisma>;
  let mockAuthService: ReturnType<typeof createIntegrationMockAuthService>;
  let mockEventService: ReturnType<typeof createIntegrationMockEventService>;

  beforeEach(() => {
    // Create fresh mocks for each test
    mockPrisma = createIntegrationMockPrisma();
    mockAuthService = createIntegrationMockAuthService();
    mockEventService = createIntegrationMockEventService();

    // Create service instance with mocks
    authModuleService = new AuthModuleService(
      mockPrisma as unknown as Parameters<typeof AuthModuleService['prototype']['constructor']>[0],
      mockAuthService as unknown as AuthService,
      mockEventService as unknown as EventService
    );
  });

  // ---------------------------------------------------------------------------
  // Complete Registration → Login → Token Refresh Flow
  // ---------------------------------------------------------------------------

  describe('Complete Auth Flow: Register → Login → Refresh', () => {
    it('should complete full authentication lifecycle', async () => {
      // STEP 1: Register a new user
      const registerData: RegisterRequest = {
        email: 'newuser@integration.test',
        password: 'SecurePassword123!',
        passwordConfirm: 'SecurePassword123!',
        firstName: 'New',
        lastName: 'User',
        phone: '+905559876543',
        acceptTerms: true,
      };

      // Setup mock for registration
      mockPrisma.user.findFirst.mockResolvedValueOnce(null); // Email not taken
      mockPrisma.user.create.mockResolvedValueOnce({
        id: 'user_new_integration',
        email: registerData.email,
        firstName: registerData.firstName,
        lastName: registerData.lastName,
        status: UserStatus.INVITED,
      });

      const registerResult = await authModuleService.register(registerData);

      // Verify registration
      expect(registerResult.userId).toBe('user_new_integration');
      expect(registerResult.email).toBe(registerData.email);
      expect(registerResult.requiresEmailVerification).toBe(true);

      // Verify registration event was emitted
      const events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'auth.user.registered')).toBe(true);

      // STEP 2: Verify email
      const verificationToken = mockAuthService.generateEmailVerificationToken.mock.results[0]?.value;
      expect(verificationToken).toBeDefined();

      // Setup mock for email verification
      const verifiedUser = createTestUser({
        id: 'user_new_integration',
        email: registerData.email,
        emailVerifiedAt: null,
        status: UserStatus.INVITED,
      });
      mockPrisma.user.update.mockResolvedValueOnce({
        ...verifiedUser,
        emailVerifiedAt: new Date(),
        status: UserStatus.ACTIVE,
      });

      const verifyResult = await authModuleService.verifyEmail({
        token: await verificationToken,
      });

      expect(verifyResult.verified).toBe(true);

      // STEP 3: Login with verified account
      const loginData: LoginRequest = {
        email: registerData.email,
        password: registerData.password,
      };

      // Setup mock for login
      const activeUser = createTestUser({
        id: 'user_new_integration',
        email: registerData.email,
        passwordHash: `hashed_${registerData.password}_1234567890`,
        firstName: registerData.firstName,
        lastName: registerData.lastName,
        status: UserStatus.ACTIVE,
        emailVerifiedAt: new Date(),
      });

      mockPrisma.user.findFirst.mockResolvedValueOnce(activeUser);
      mockPrisma.user.update.mockResolvedValueOnce(activeUser); // lastLoginAt update

      const loginResult = await authModuleService.login(loginData, {
        ipAddress: '192.168.1.100',
        userAgent: 'Integration Test Agent',
      });

      // Verify login
      expect(loginResult.user.id).toBe('user_new_integration');
      expect(loginResult.user.email).toBe(registerData.email);
      expect(loginResult.user.emailVerified).toBe(true);
      expect(loginResult.tokens.accessToken).toBeDefined();
      expect(loginResult.tokens.refreshToken).toBeDefined();

      // Verify login event
      const loginEvents = mockEventService.getEmittedEvents();
      expect(loginEvents.some((e) => e.event === 'auth.login')).toBe(true);

      // STEP 4: Refresh tokens
      const refreshToken = loginResult.tokens.refreshToken;

      // Setup mock for token refresh (user lookup callback)
      mockPrisma.user.findFirst.mockResolvedValueOnce(activeUser);

      const refreshResult = await authModuleService.refreshTokens(refreshToken);

      // Verify refresh
      expect(refreshResult.tokens.accessToken).toBeDefined();
      expect(refreshResult.tokens.refreshToken).toBeDefined();
      // New tokens should be different from original
      expect(refreshResult.tokens.accessToken).not.toBe(loginResult.tokens.accessToken);
      expect(refreshResult.tokens.refreshToken).not.toBe(loginResult.tokens.refreshToken);

      // Verify refresh event
      const refreshEvents = mockEventService.getEmittedEvents();
      expect(refreshEvents.some((e) => e.event === 'auth.token.refresh')).toBe(true);
    });

    it('should prevent login with unverified email and show correct status', async () => {
      // Setup: User with unverified email
      const unverifiedUser = createTestUser({
        emailVerifiedAt: null,
        status: UserStatus.INVITED,
      });

      mockPrisma.user.findFirst.mockResolvedValueOnce(unverifiedUser);
      mockPrisma.user.update.mockResolvedValueOnce(unverifiedUser);

      // Login should succeed but show email not verified
      const loginResult = await authModuleService.login({
        email: unverifiedUser.email,
        password: 'SecurePassword123!',
      });

      expect(loginResult.user.emailVerified).toBe(false);
      expect(loginResult.tokens.accessToken).toBeDefined();
    });
  });

  // ---------------------------------------------------------------------------
  // Password Reset Flow
  // ---------------------------------------------------------------------------

  describe('Password Reset Flow', () => {
    it('should complete password reset cycle', async () => {
      const testUser = createTestUser();

      // STEP 1: Request password reset
      mockPrisma.user.findFirst.mockResolvedValueOnce(testUser);

      const forgotResult = await authModuleService.forgotPassword({
        email: testUser.email,
      });

      expect(forgotResult.message).toBeDefined();
      expect(mockAuthService.generatePasswordResetToken).toHaveBeenCalledWith(
        testUser.id,
        testUser.email
      );

      // Verify event emitted
      const events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'auth.password.reset.requested')).toBe(true);

      // STEP 2: Reset password with token
      const resetToken = await mockAuthService.generatePasswordResetToken.mock.results[0]?.value;

      mockPrisma.user.update.mockResolvedValueOnce({
        ...testUser,
        passwordHash: 'hashed_NewSecurePassword456!_newtime',
      });

      const resetResult = await authModuleService.resetPassword({
        token: resetToken,
        password: 'NewSecurePassword456!',
        passwordConfirm: 'NewSecurePassword456!',
      });

      expect(resetResult.message).toContain('successfully');

      // Verify password was hashed
      expect(mockAuthService.hashPassword).toHaveBeenCalledWith('NewSecurePassword456!');

      // Verify all sessions were revoked (security)
      expect(mockAuthService.revokeAllUserTokens).toHaveBeenCalledWith(testUser.id);

      // Verify reset token was invalidated
      expect(mockAuthService.invalidatePasswordResetToken).toHaveBeenCalledWith(resetToken);

      // Verify event emitted
      const resetEvents = mockEventService.getEmittedEvents();
      expect(resetEvents.some((e) => e.event === 'auth.password.reset.completed')).toBe(true);

      // STEP 3: Login with new password
      mockPrisma.user.findFirst.mockResolvedValueOnce({
        ...testUser,
        passwordHash: 'hashed_NewSecurePassword456!_newtime',
      });
      mockPrisma.user.update.mockResolvedValueOnce(testUser);

      // Update mock to accept new password
      mockAuthService.verifyPassword.mockResolvedValueOnce(true);

      const loginResult = await authModuleService.login({
        email: testUser.email,
        password: 'NewSecurePassword456!',
      });

      expect(loginResult.user.email).toBe(testUser.email);
      expect(loginResult.tokens.accessToken).toBeDefined();
    });

    it('should not reveal if email exists (prevent enumeration)', async () => {
      // Request reset for non-existent email
      mockPrisma.user.findFirst.mockResolvedValueOnce(null);

      const result = await authModuleService.forgotPassword({
        email: 'nonexistent@test.com',
      });

      // Should still return success message
      expect(result.message).toBeDefined();
      expect(result.message).toContain('If an account exists');

      // Should NOT generate token for non-existent user
      expect(mockAuthService.generatePasswordResetToken).not.toHaveBeenCalled();
    });

    it('should reject invalid reset token', async () => {
      await expect(
        authModuleService.resetPassword({
          token: 'invalid_token_xyz',
          password: 'NewPassword123!',
          passwordConfirm: 'NewPassword123!',
        })
      ).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Email Verification Flow
  // ---------------------------------------------------------------------------

  describe('Email Verification Flow', () => {
    it('should complete email verification and activate account', async () => {
      const unverifiedUser = createTestUser({
        emailVerifiedAt: null,
        status: UserStatus.INVITED,
      });

      // Generate verification token (simulating registration)
      mockPrisma.user.findFirst.mockResolvedValueOnce(null);
      mockPrisma.user.create.mockResolvedValueOnce(unverifiedUser);

      await authModuleService.register({
        email: unverifiedUser.email,
        password: 'Password123!',
        passwordConfirm: 'Password123!',
        firstName: unverifiedUser.firstName,
        lastName: unverifiedUser.lastName,
        acceptTerms: true,
      });

      const verificationToken = await mockAuthService.generateEmailVerificationToken.mock.results[0]?.value;

      // Verify email
      mockPrisma.user.update.mockResolvedValueOnce({
        ...unverifiedUser,
        emailVerifiedAt: new Date(),
        status: UserStatus.ACTIVE,
      });

      const result = await authModuleService.verifyEmail({
        token: verificationToken,
      });

      expect(result.verified).toBe(true);

      // Verify user was updated correctly
      expect(mockPrisma.user.update).toHaveBeenCalledWith({
        where: { id: unverifiedUser.id },
        data: {
          emailVerifiedAt: expect.any(Date),
          status: UserStatus.ACTIVE,
        },
      });

      // Verify event emitted
      const events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'auth.email.verification.completed')).toBe(true);
    });

    it('should allow resending verification email', async () => {
      const unverifiedUser = createTestUser({
        emailVerifiedAt: null,
        status: UserStatus.INVITED,
      });

      mockPrisma.user.findFirst.mockResolvedValueOnce(unverifiedUser);

      const result = await authModuleService.resendVerification({
        email: unverifiedUser.email,
      });

      expect(result.message).toBeDefined();
      expect(mockAuthService.generateEmailVerificationToken).toHaveBeenCalledWith(
        unverifiedUser.id,
        unverifiedUser.email
      );
    });

    it('should not resend to already verified email', async () => {
      const verifiedUser = createTestUser({
        emailVerifiedAt: new Date(),
        status: UserStatus.ACTIVE,
      });

      mockPrisma.user.findFirst.mockResolvedValueOnce(verifiedUser);

      const result = await authModuleService.resendVerification({
        email: verifiedUser.email,
      });

      // Should return success but NOT generate new token
      expect(result.message).toBeDefined();
      expect(mockAuthService.generateEmailVerificationToken).not.toHaveBeenCalled();
    });
  });

  // ---------------------------------------------------------------------------
  // Session Management Flow
  // ---------------------------------------------------------------------------

  describe('Session Management Flow', () => {
    it('should logout from single session', async () => {
      const result = await authModuleService.logout('user_123', 'token_456', {
        allDevices: false,
      });

      expect(result.message).toContain('logged out');

      // Verify event emitted
      const events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'auth.logout')).toBe(true);
    });

    it('should logout from all devices and revoke all tokens', async () => {
      const result = await authModuleService.logout('user_123', 'token_456', {
        allDevices: true,
      });

      expect(result.message).toContain('all devices');
      expect(mockAuthService.revokeAllUserTokens).toHaveBeenCalledWith('user_123');

      // Verify event emitted
      const events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'auth.session.revoked.all')).toBe(true);
    });

    it('should list active sessions with current session marked', async () => {
      const sessions = [
        {
          tokenId: 'token_1',
          userId: 'user_123',
          organizationId: 'org_123',
          role: 'owner',
          ipAddress: '192.168.1.1',
          userAgent: 'Chrome',
          createdAt: new Date().toISOString(),
          lastActivityAt: new Date().toISOString(),
        },
        {
          tokenId: 'token_2',
          userId: 'user_123',
          organizationId: 'org_123',
          role: 'owner',
          ipAddress: '192.168.1.2',
          userAgent: 'Firefox',
          createdAt: new Date().toISOString(),
          lastActivityAt: new Date().toISOString(),
        },
      ];

      mockAuthService.getUserSessions.mockResolvedValueOnce(sessions);

      const result = await authModuleService.getSessions('user_123', 'token_1');

      expect(result).toHaveLength(2);
      expect(result[0]?.isCurrent).toBe(true);
      expect(result[1]?.isCurrent).toBe(false);
    });
  });

  // ---------------------------------------------------------------------------
  // Change Password Flow
  // ---------------------------------------------------------------------------

  describe('Change Password Flow', () => {
    it('should change password and revoke all sessions', async () => {
      const testUser = createTestUser();

      mockPrisma.user.findUnique.mockResolvedValueOnce(testUser);
      mockAuthService.verifyPassword.mockResolvedValueOnce(true);
      mockPrisma.user.update.mockResolvedValueOnce({
        ...testUser,
        passwordHash: 'hashed_NewPassword789!_newtime',
      });

      const result = await authModuleService.changePassword(testUser.id, {
        currentPassword: 'SecurePassword123!',
        newPassword: 'NewPassword789!',
        newPasswordConfirm: 'NewPassword789!',
      });

      expect(result.message).toContain('successfully');
      expect(result.sessionsRevoked).toBe(true);

      // Verify current password was verified
      expect(mockAuthService.verifyPassword).toHaveBeenCalledWith(
        'SecurePassword123!',
        testUser.passwordHash
      );

      // Verify new password was hashed
      expect(mockAuthService.hashPassword).toHaveBeenCalledWith('NewPassword789!');

      // Verify all sessions were revoked
      expect(mockAuthService.revokeAllUserTokens).toHaveBeenCalledWith(testUser.id);

      // Verify event emitted
      const events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'auth.password.changed')).toBe(true);
    });

    it('should reject incorrect current password', async () => {
      const testUser = createTestUser();

      mockPrisma.user.findUnique.mockResolvedValueOnce(testUser);
      mockAuthService.verifyPassword.mockResolvedValueOnce(false);

      await expect(
        authModuleService.changePassword(testUser.id, {
          currentPassword: 'WrongPassword123!',
          newPassword: 'NewPassword789!',
          newPasswordConfirm: 'NewPassword789!',
        })
      ).rejects.toThrow(AppException);

      // Should not update password
      expect(mockPrisma.user.update).not.toHaveBeenCalled();
    });
  });

  // ---------------------------------------------------------------------------
  // Error Handling & Edge Cases
  // ---------------------------------------------------------------------------

  describe('Error Handling', () => {
    it('should reject registration with duplicate email', async () => {
      const existingUser = createTestUser();
      mockPrisma.user.findFirst.mockResolvedValueOnce(existingUser);

      await expect(
        authModuleService.register({
          email: existingUser.email,
          password: 'Password123!',
          passwordConfirm: 'Password123!',
          firstName: 'Test',
          lastName: 'User',
          acceptTerms: true,
        })
      ).rejects.toThrow(AppException);
    });

    it('should reject login with suspended account', async () => {
      const suspendedUser = createTestUser({ status: UserStatus.SUSPENDED });
      mockPrisma.user.findFirst.mockResolvedValueOnce(suspendedUser);

      await expect(
        authModuleService.login({
          email: suspendedUser.email,
          password: 'Password123!',
        })
      ).rejects.toThrow(AppException);
    });

    it('should reject login with incorrect password', async () => {
      const testUser = createTestUser();
      mockPrisma.user.findFirst.mockResolvedValueOnce(testUser);
      mockAuthService.verifyPassword.mockResolvedValueOnce(false);

      await expect(
        authModuleService.login({
          email: testUser.email,
          password: 'WrongPassword!',
        })
      ).rejects.toThrow(AppException);

      // Should emit failed login event
      const events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'auth.login.failed')).toBe(true);
    });

    it('should reject empty refresh token', async () => {
      await expect(authModuleService.refreshTokens('')).rejects.toThrow(AppException);
    });

    it('should handle validation errors for invalid email format', async () => {
      await expect(
        authModuleService.register({
          email: 'invalid-email',
          password: 'Password123!',
          passwordConfirm: 'Password123!',
          firstName: 'Test',
          lastName: 'User',
          acceptTerms: true,
        })
      ).rejects.toThrow(AppException);
    });

    it('should handle validation errors for password mismatch', async () => {
      await expect(
        authModuleService.register({
          email: 'test@example.com',
          password: 'Password123!',
          passwordConfirm: 'DifferentPassword123!',
          firstName: 'Test',
          lastName: 'User',
          acceptTerms: true,
        })
      ).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Multi-Tenant Considerations
  // ---------------------------------------------------------------------------

  describe('Multi-Tenant Auth', () => {
    it('should include organizationId in token payload', async () => {
      const testUser = createTestUser({
